const SUPABASE_URL = 'https://hkqssbomrcbtfbdowtgj.supabase.co';
const SUPABASE_KEY = 'REDACTED_SUPABASE_SERVICE_KEY';
const AIMFOX_TOKEN = 'Bearer 8e65df8c-3fe2-4ecf-bf05-8261ea85464b';
const FETCH_CONTEXT_URL = 'https://n8n-1404.n8n.whiteserverdns.com/webhook/mco-fetch-context';
const WRITE_EVENT_URL = 'https://n8n-1404.n8n.whiteserverdns.com/webhook/mco-write-event';
// Create a list-type campaign in Aimfox dashboard named 'MCO LinkedIn Follow-Up'
// with first message = {{CUSTOM_MESSAGE}}, then paste its ID here:
const AIMFOX_FOLLOWUP_CAMPAIGN_ID = '39a3ee2f-8474-4e9a-b498-81d14e319788';

const body = $input.first().json.body || $input.first().json;

const required = ['lead_email', 'target_channel', 'queue_id'];
const missing = required.filter(f => !body[f]);
if (missing.length > 0) throw new Error('Missing fields: ' + missing.join(', '));

const validChannels = ['email', 'linkedin', 'sms'];
if (!validChannels.includes(body.target_channel)) {
  throw new Error('Unsupported target_channel: ' + body.target_channel);
}

return [{ json: {
  SUPABASE_URL,
  SUPABASE_KEY,
  AIMFOX_TOKEN,
  FETCH_CONTEXT_URL,
  WRITE_EVENT_URL,
  AIMFOX_FOLLOWUP_CAMPAIGN_ID,
  lead_email:          body.lead_email.toLowerCase().trim(),
  target_channel:      body.target_channel,
  queue_id:            body.queue_id,
  trigger_channel:     body.trigger_channel || 'unknown',
  follow_up_context:   body.follow_up_context || '',
  linkedin_profile_url: body.linkedin_profile_url || null
}}];

const setup = $('Setup & Validate').first().json;
const ctx = $input.first().json;
const lead = ctx.lead || {};
return [{ json: {
  ...setup,
  context_block:  ctx.context_block || '(No prior conversation history.)',
  overall_intent: ctx.overall_intent || 'unknown',
  lead_name:      lead.full_name || lead.lead_email || setup.lead_email,
  lead_company:   lead.company || '',
  linkedin_profile_url: setup.linkedin_profile_url || lead.linkedin_profile_url || null
}}];

const setup = $('Merge Context').first().json;
const aiOutput = $input.first().json;
const message = (aiOutput.text || aiOutput.output || '').trim();
if (!message) throw new Error('Email AI returned empty message');
return [{ json: { ...setup, generated_message: message, sent_channel: 'email' } }];

const setup = $('Merge Context').first().json;
const aiOutput = $input.first().json;
const message = (aiOutput.text || aiOutput.output || '').trim();
if (!message) throw new Error('LinkedIn AI returned empty message');
if (!setup.linkedin_profile_url) {
  // No profile URL — mark as skipped cleanly instead of crashing
  return [{ json: { ...setup, generated_message: message, sent_channel: 'linkedin', skipped: true, skip_reason: 'No linkedin_profile_url for this lead' } }];
}
return [{ json: { ...setup, generated_message: message, sent_channel: 'linkedin', skipped: false } }];

// Lead skipped — no linkedin_profile_url available
const d = $input.first().json;
console.log('LinkedIn follow-up skipped for', d.lead_email, '—', d.skip_reason);
return [{ json: { ...d, send_status: 'skipped' } }];

// Converge all branches — data is already on the item
const d = $input.first().json;
return [{ json: { ...d, send_status: d.send_status || 'sent' } }];

